SELECT COUNT(*) 
FROM user 
WHERE create_time BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(DISTINCT user_id) 
FROM user 
WHERE last_login_time BETWEEN #{startTime} AND #{endTime}

